  "originalFile": "/**
 * 统一API响应类型定义
 * 为整个前端应用提供类型安全的API响应处理基础
 */

import { AxiosResponse, InternalAxiosRequestConfig } from 'axios';

// ==================== 基础响应类型 ====================

/**
 * 标准API响应格式
 * 适用于大部分后端API接口
 */
export interface StandardApiResponse<T = unknown> {
  isSuccess: boolean;
  data: T;
  message?: string;
  code?: string;
  timestamp?: string;
}

/**
 * 分页响应格式
 * 适用于列表类API接口
 */
export interface PaginatedApiResponse<T = unknown> {
  isSuccess: boolean;
  data: {
    items: T[];
    pagination: {
      page: number;
      pageSize: number;
      total: number;
      totalPages: number;
    };
  };
  message?: string;
}

/**
 * 简化响应格式
 * 直接返回数据，无包装结构
 */
export interface DirectResponse<T = unknown> {
  [key: string]: T;
}

/**
 * 错误响应格式
 */
export interface ErrorResponse {
  isSuccess: false;
  error: {
    code: string;
    message: string;
    details?: Record<string, unknown>;
    timestamp?: string;
  };
}

// ==================== 业务响应类型 ====================

import { User } from './auth';

/**
 * 用户认证响应
 */
export interface AuthResponse {
  user: User;
  tokens: {
    access_token: string;
    refresh_token: string;
    token_type: string;
    expires_in: number;
  };
  permissions: Array<{
    resource: string;
    action: string;
    description?: string;
  }>;
}

/**
 * 资产列表响应
 */
export interface AssetListResponse {
  items: unknown[];
  total: number;
  page: number;
  pageSize: number;
  pages: number;
}

// ==================== 响应提取器类型 ====================

/**
 * 响应数据提取结果
 */
export interface ExtractResult<T> {
  isSuccess: boolean;
  data?: T;
  error?: string;
  rawResponse: AxiosResponse;
}

/**
 * 响应检测配置
 */
export interface ResponseDetectionConfig {
  // 成功检测字段
  successField?: string;
  // 数据字段
  dataField?: string;
  // 错误检测
  errorFields?: string[];
  // 是否启用严格模式
  strict?: boolean;
}

/**
 * 智能响应提取选项
 */
export interface SmartExtractOptions<T = unknown> {
  // 期望的数据类型
  expectedType?: new (...args: unknown[]) => T;
  // 自定义检测配置
  detection?: ResponseDetectionConfig;
  // 是否启用类型验证
  enableTypeValidation?: boolean;
  // 默认值
  defaultValue?: T;
}

// ==================== 错误处理类型 ====================

/**
 * API错误分类
 */
export enum ApiErrorType {
  NETWORK_ERROR = 'NETWORK_ERROR',
  SERVER_ERROR = 'SERVER_ERROR',
  CLIENT_ERROR = 'CLIENT_ERROR',
  AUTH_ERROR = 'AUTH_ERROR',
  VALIDATION_ERROR = 'VALIDATION_ERROR',
  BUSINESS_ERROR = 'BUSINESS_ERROR',
  UNKNOWN_ERROR = 'UNKNOWN_ERROR',
}

/**
 * 增强的API错误信息
 */
export interface ApiClientError {
  type: ApiErrorType;
  code: string;
  message: string;
  details?: Record<string, unknown>;
  timestamp: string;
  requestId?: string;
  statusCode?: number;
  originalError?: Error | unknown;
}

// ==================== 重试和缓存类型 ====================

/**
 * 重试配置
 */
export interface RetryConfig {
  maxAttempts: number;
  delay: number;
  backoffMultiplier: number;
  retryCondition?: (error: Error | unknown) => boolean;
}

/**
 * 缓存配置
 */
export interface CacheConfig {
  enabled: boolean;
  ttl: number; // 生存时间（毫秒）
  keyGenerator?: (config: Record<string, unknown>) => string;
  maxSize?: number;
}

// ==================== 统一API客户端配置 ====================

/**
 * 增强API客户端配置
 */
export interface ApiClientConfig {
  // 基础配置
  baseURL?: string;
  timeout?: number;

  // 响应处理配置
  responseDetection?: ResponseDetectionConfig;
  defaultRetryConfig?: RetryConfig;
  defaultCacheConfig?: CacheConfig;

  // 功能开关
  enableAutoRetry?: boolean;
  enableCaching?: boolean;
  enableLogging?: boolean;
  enableTypeValidation?: boolean;

  // 错误处理
  globalErrorHandler?: (error: ApiClientError) => void;

  // 拦截器
  requestInterceptors?: Array<(config: InternalAxiosRequestConfig) => InternalAxiosRequestConfig>;
  responseInterceptors?: Array<(response: AxiosResponse) => AxiosResponse>;
}

// ==================== 类型守卫和工具函数 ====================

/**
 * 检查是否为标准API响应
 */
export function isStandardApiResponse(response: unknown): response is StandardApiResponse {
  if (response === null || response === undefined) return false;
  if (typeof response !== 'object') return false;
  const obj = response as Record<string, unknown>;
  return 'success' in obj && typeof obj.success === 'boolean';
}

/**
 * 检查是否为分页响应
 */
export function isPaginatedResponse(response: unknown): response is PaginatedApiResponse {
  if (!isStandardApiResponse(response)) return false;
  const data = response.data;
  if (data === null || data === undefined || typeof data !== 'object') return false;
  return 'items' in data && 'pagination' in data;
}

/**
 * 检查是否为错误响应
 */
export function isErrorResponse(response: unknown): response is ErrorResponse {
  if (response === null || response === undefined) return false;
  if (typeof response !== 'object') return false;
  const obj = response as Record<string, unknown>;
  return obj.success === false && 'error' in obj;
}

/**
 * 检查是否为直接数据响应
 */
export function isDirectResponse<T>(response: unknown): response is DirectResponse<T> {
  if (response === null || response === undefined) return false;
  if (typeof response !== 'object') return false;
  return !('success' in response);
}

